import{_ as a,C as i,o as t,c as r,ai as e,E as d}from"./chunks/framework.BIXs0jTs.js";const n="/assets/preface-cover.Balx8Fq4.png",P=JSON.parse('{"title":"前言","description":"","frontmatter":{"title":"前言","outline":"deep"},"headers":[],"relativePath":"00-preface/index.md","filePath":"00-preface/index.md","lastUpdated":null}'),s={name:"00-preface/index.md"};function C(p,l,u,g,c,h){const o=i("Mermaid");return t(),r("div",null,[l[0]||(l[0]=e('<h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h1><p><img src="'+n+'" alt="前言：工程世界的复杂性与挑战"></p><blockquote><p><strong>这不是一本“玩 AI”的书，而是一本教你把 Claude Code 当作工程基础设施来用的书。</strong></p></blockquote><p>过去几年里，AI 编程工具从“写几行函数的小助手”，进化成了可以读完整个代码库、批量重构、跑测试、看日志、生成文档的<strong>工程级代理（Agent）</strong>。<br> Claude Code 正是这类工具中的代表：它并不是一个简单的聊天机器人，而是一个可以在你的项目里<strong>持续工作</strong>的工程伙伴。</p><p>本书的写作目的，就是回答三个问题：</p><ul><li><strong>如果我已经会写代码，还需要 Claude Code 吗？</strong></li><li><strong>在真实的工程环境里，我应该怎样安全、高效地使用 Claude Code？</strong></li><li><strong>怎样把 Claude Code 和 Skill、MCP 结合起来，变成我和团队的“可编程开发平台”？</strong></li></ul><p>为了回答这三个问题，本书会从最基础的使用方式开始，一步步带你走向更高阶的工程实践。</p><h2 id="本书面向谁" tabindex="-1">本书面向谁？ <a class="header-anchor" href="#本书面向谁" aria-label="Permalink to &quot;本书面向谁？&quot;">​</a></h2><p>本书主要面向以下几类读者：</p><ul><li>已经熟悉至少一门主流编程语言（如 TypeScript、Python、Go、Java 等）的工程师；</li><li>在公司或个人项目中维护真实线上系统，而不仅仅是刷题或做 Demo；</li><li>正在使用或计划使用 Claude Code，希望<strong>系统掌握工程化用法</strong>；</li><li>想要在团队内推广 AI 编程实践，却苦于缺少一套成体系的教材或规范。</li></ul><p>如果你刚刚接触编程，或者希望从零开始学习编程语言本身，本书可能<strong>不会</strong>是最合适的起点；<br> 但如果你已经能独立完成小型/中型项目，却总觉得“时间不够用、重构来不及、测试写不完”，那么这本书就是为你准备的。</p><h2 id="本书讲什么-——从-claude-code-到-skill-和-mcp" tabindex="-1">本书讲什么？——从 Claude Code 到 Skill 和 MCP <a class="header-anchor" href="#本书讲什么-——从-claude-code-到-skill-和-mcp" aria-label="Permalink to &quot;本书讲什么？——从 Claude Code 到 Skill 和 MCP&quot;">​</a></h2><p>本书围绕三条主线展开，它们也是全书的三个关键词：</p><ul><li><p><strong>Claude Code</strong>：<br> 终端中的工程代理，可以读写文件、执行命令、跑测试、解析日志，是整套体系的“执行中枢”。</p></li><li><p><strong>Skill</strong>：<br> 把高频任务抽象成<strong>可复用的能力单元</strong>。例如：</p><ul><li>“根据 git diff 生成规范的 commit message”；</li><li>“分析错误日志，给出排查步骤和可能根因”；</li><li>“为某个模块生成测试用例列表并补充单元测试”。<br> Skill 让 Claude Code 从“聪明的聊天对象”进化成“有明确按钮和菜单的工具箱”。</li></ul></li><li><p><strong>MCP（Model/Agent Context Protocol）</strong>：<br> 把外部世界（数据库、Issue 系统、CI、监控、知识库……）接入 Claude Code 的通用协议。<br> 有了 MCP，Claude Code 不再只懂代码和文件，还能<strong>安全地调用外部工具和数据源</strong>。</p></li></ul><p>你可以把这三者想象成一张简化的“分层示意图”：</p>',15)),d(o,{id:"mermaid_64a570aa",graph:"flowchart%20TB%0A%20%20Code%5B%22%E4%BB%A3%E7%A0%81%E4%B8%8E%E5%9F%BA%E7%A1%80%E8%AE%BE%E6%96%BD%22%5D%20--%3E%20MCP%5B%22%E5%B7%A5%E5%85%B7%E4%B8%8E%E8%B5%84%E6%BA%90%EF%BC%88MCP%EF%BC%89%22%5D%0A%20%20MCP%20--%3E%20Skill%5B%22%E4%BB%BB%E5%8A%A1%E7%BA%A7%20Skill%22%5D%0A%20%20Skill%20--%3E%20Claude%5B%22Claude%20Code%22%5D%0A%20%20Dev%5B%22%E5%BC%80%E5%8F%91%E8%80%85%22%5D%20%3C--%3E%20Claude"}),l[1]||(l[1]=e('<h2 id="如何阅读本书" tabindex="-1">如何阅读本书？ <a class="header-anchor" href="#如何阅读本书" aria-label="Permalink to &quot;如何阅读本书？&quot;">​</a></h2><p>如果你是第一次系统接触 Claude Code，推荐按照以下顺序阅读：</p><ol><li><p><strong>第 I 部分：Claude Code 基础与工作流</strong><br> 了解 Claude Code 的定位、核心能力、常用模式（Ask / Plan / Agent / Debug 等），以及如何在日常开发中嵌入它。</p></li><li><p><strong>第 II 部分：Skill——把任务变成可复用的能力</strong><br> 学会识别适合抽象为 Skill 的高频任务，设计 Skill 的输入输出，并实现第一个真正对你有帮助的 Skill。</p></li><li><p><strong>第 III 部分：MCP——连接外部世界</strong><br> 掌握 MCP 的基本概念与实现方式，让 Claude Code 能够安全地访问日志系统、Issue 系统、监控和数据库等。</p></li><li><p><strong>第 IV 部分：项目与团队实战</strong><br> 通过完整案例，看如何在一个具体项目和一个真实团队中，落地上述所有能力。</p></li></ol><p>如果你已经在日常工作中大量使用 Claude Code，也可以带着问题<strong>跳读某些部分</strong>，例如：</p><ul><li>想提高复用性和团队协作：优先阅读 Skill 相关章节；</li><li>想把 Claude Code 接入现有平台：优先阅读 MCP 相关章节；</li><li>想梳理团队规范：优先阅读团队与项目实战章节。</li></ul><h2 id="代码示例与技术栈说明" tabindex="-1">代码示例与技术栈说明 <a class="header-anchor" href="#代码示例与技术栈说明" aria-label="Permalink to &quot;代码示例与技术栈说明&quot;">​</a></h2><p>本书中的示例代码，会优先使用以下两种技术栈展示：</p><ul><li><strong>TypeScript / Node.js</strong>：前后端皆可，生态丰富，适合演示服务端与工具链集成；</li><li><strong>Python</strong>：在后端服务、数据工程与自动化脚本领域应用广泛。</li></ul><p>在大多数情况下，我们会先给出<strong>与语言无关的概念与工作流</strong>，再在需要落地到代码时，提供 TypeScript 和/或 Python 的示例版本。<br> 如果你使用的是其他语言（例如 Go、Java、Rust 等），也可以将这些示例视为“伪代码”，按思路迁移到自己的技术栈中。</p><p>所有示例代码都会托管在本书配套的公开仓库中，你可以：</p><ul><li>直接克隆仓库，在本地运行和修改；</li><li>按章节目录查找对应示例；</li><li>在阅读时配合实际代码，更直观地理解 Claude Code 的工作方式。</li></ul><h2 id="关于版本与预览版" tabindex="-1">关于版本与预览版 <a class="header-anchor" href="#关于版本与预览版" aria-label="Permalink to &quot;关于版本与预览版&quot;">​</a></h2><p>你现在阅读的是<strong>预览版</strong>，这意味着：</p><ul><li>内容仍在不断演进，会根据 Claude Code / Skill / MCP 的最新能力进行更新；</li><li>某些章节可能以“草稿”形式出现，后续会逐步补充更多案例和插图；</li><li>读者的反馈会直接影响正式出版版本的结构与重点。</li></ul><p>为了方便引用和追踪变化，本书会在 <code>book.config.json</code> 与站点首页中标注当前版本号，例如：<code>0.1.0‑draft</code>。<br> 当出现重要更新（例如 Claude Code 新增关键能力，或 MCP 协议有重大变化）时，我们会：</p><ul><li>更新在线版本的对应章节；</li><li>在变更记录中注明此次更新涉及的章节与要点。</li></ul><h2 id="你可以从这本书中获得什么" tabindex="-1">你可以从这本书中获得什么？ <a class="header-anchor" href="#你可以从这本书中获得什么" aria-label="Permalink to &quot;你可以从这本书中获得什么？&quot;">​</a></h2><p>如果一切顺利，当你读完并实践完本书后，你应该能够：</p><ul><li>为自己的项目设计一套<strong>稳定、可复用的 Claude Code 使用方式</strong>；</li><li>用 Skill 把高频任务沉淀成团队共用的“工具按钮”；</li><li>用 MCP 把现有的工程基础设施（日志、监控、Issue、CI 等）联通给 Claude Code；</li><li>在团队层面制定一份可落地的《Claude Code 使用规范》。</li></ul><p>更重要的是，你会逐渐形成一种新的思维方式：<br><strong>遇到工程问题时，不再只想着“我怎么写代码解决”，而是会同时思考“我怎样设计一个 Skill 或 MCP，让 Claude Code 帮我和团队一起解决”。</strong></p><p>希望这本书能成为你在 Claude Code 时代的第一本系统实践手册，也希望你在阅读过程中，多多思考、尝试和反馈，让它变得越来越好。</p>',21))])}const b=a(s,[["render",C]]);export{P as __pageData,b as default};
